6: public class AboutAsserts : Koan
7: {
8: 	//We shall contemplate truth by testing reality, via asserts.
9: 	[Step(1)]
10: 	public void AssertTruth()
11: 	{
12: 		Assert.True(false); //This should be true
13: 	}
14: 
15: 	//Enlightenment may be more easily achieved with appropriate messages
16: 	[Step(2)]
17: 	public void AssertTruthWithMessage()
18: 	{
19: 		Assert.True(false, "This should be true -- Please fix this");
20: 	}
21: 
22: 	//To understand reality, we must compare our expectations against reality
23: 	[Step(3)]
24: 	public void AssertEquality()
25: 	{
26: 		var expectedValue = 3;
27: 		var actualValue = 1 + 1;
28: 		Assert.True(expectedValue == actualValue);
29: 	}
30: 
31: 	//Some ways of asserting equality are better than others
32: 	[Step(4)]
33: 	public void ABetterWayOfAssertingEquality()
34: 	{
35: 		var expectedValue = 3;
36: 		var actualValue = 1 + 1;
37: 		Assert.Equal(expectedValue, actualValue);
38: 	}
39: 
40: 	//Sometimes we will ask you to fill in the values
41: 	[Step(5)]
42: 	public void FillInValues()
43: 	{
44: 		Assert.Equal(FILL_ME_IN, 1 + 1);
45: 	}
46: }","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/DotNetKoans--dibench@dfc61171effb00d16ea1e4bd7bd44e2eced84484/-/blob/Koans/AboutAsserts.cs"}

