        {
            try
            {
                ForEachStep(step =>
                {
                    sensei.Observe(step.Meditate());
                });
            }
            catch (SenseiException e)
            { }

            sensei.Instruct(this);

            return sensei.Failed() ? -1 : 0;
        }

